+                            <p class="detail-title">@selectedEmployee.Title</p>
+                            <span class="department-badge" style="background-color: @GetDepartmentColor(selectedEmployee.Department)">@selectedEmployee.Department</span>
+                            <p class="detail-location">📍 @selectedEmployee.Location</p>
+                        </div>
+                    </div>
+
+                    <div class="info-grid">
+                        <div class="info-item">
+                            <span class="info-label">Email</span>
+                            <span class="info-value">@selectedEmployee.Email</span>
+                        </div>
+                        <div class="info-item">
+                            <span class="info-label">Hire Date</span>
+                            <span class="info-value">@selectedEmployee.HireDate.ToString("MMMM dd, yyyy")</span>
+                        </div>
+                        <div class="info-item">
+                            <span class="info-label">Tenure</span>
+                            <span class="info-value">@GetTenureYears(selectedEmployee.HireDate) years</span>
+                        </div>
+                        <div class="info-item">
+                            <span class="info-label">Manager</span>
+                            <span class="info-value">@selectedEmployee.ManagerName</span>
+                        </div>
+                    </div>
+
+                    <div class="direct-reports-section">
+                        <h3>Direct Reports</h3>
+                        @if (directReports is null)
+                        {
+                            <p>Loading...</p>
+                        }
+                        else if (directReports.Count == 0)
+                        {
+                            <p>No direct reports</p>
+                        }
+                        else
+                        {
+                            <div class="direct-reports-list">
+                                @foreach (var report in directReports)
+                                {
+                                    <div class="employee-card clickable" @onclick="() => SelectEmployee(report)">
+                                        <div class="avatar-circle">@GetInitials(report.Name)</div>
+                                        <div class="card-info">
+                                            <span class="card-name">@report.Name</span>
+                                            <span class="card-title">@report.Title</span>
+                                            <span class="department-badge" style="background-color: @GetDepartmentColor(report.Department)">@report.Department</span>
+                                        </div>
+                                    </div>
+                                }
+                            </div>
+                        }
+                    </div>
+                </div>
+            }
+        </main>
+    </div>
+
+    @* Footer *@
+    <div class="directory-footer">
+        <span>Showing @filteredEmployees.Count of @totalEmployees employees</span>
+    </div>
+</div>
+
+@code {
+    private string? searchQuery;
+    private string? selectedDepartment;
+    private string? selectedLocation;
+
+    private List<string> departments = new();
+    private List<string> locations = new();
+    private List<Employee> filteredEmployees = new();
+    private List<Employee>? directReports;
+    private Employee? selectedEmployee;
+
+    private int totalEmployees;
+    private int numberOfDepartments;
+    private decimal averageTenure;
+    private int numberOfLocations;
+
+    protected override async Task OnInitializedAsync()
+    {
+        var summariesTask = EmployeeService.GetDepartmentSummariesAsync();
+        var departmentsTask = EmployeeService.GetDepartmentsAsync();
+        var locationsTask = EmployeeService.GetLocationsAsync();
+        var employeesTask = EmployeeService.SearchAsync(null, null, null);
+
+        await Task.WhenAll(summariesTask, departmentsTask, locationsTask, employeesTask);
+
+        var summaries = summariesTask.Result;
+        departments = departmentsTask.Result;
+        locations = locationsTask.Result;
+        filteredEmployees = employeesTask.Result;
+
+        totalEmployees = summaries.Sum(s => s.HeadCount);
+        numberOfDepartments = summaries.Count;
+        averageTenure = summaries.Count > 0
+            ? summaries.Sum(s => s.AverageTenureYears * s.HeadCount) / totalEmployees
+            : 0;
+        numberOfLocations = locations.Count;
+    }
+
+    private async Task ApplyFilters()
+    {
+        filteredEmployees = await EmployeeService.SearchAsync(
+            string.IsNullOrWhiteSpace(searchQuery) ? null : searchQuery,
+            string.IsNullOrWhiteSpace(selectedDepartment) ? null : selectedDepartment,
+            string.IsNullOrWhiteSpace(selectedLocation) ? null : selectedLocation);
+    }
+
+    private async Task ClearFilters()
+    {
+        searchQuery = null;
+        selectedDepartment = null;
+        selectedLocation = null;
+        filteredEmployees = await EmployeeService.SearchAsync(null, null, null);
+    }
+
+    private async Task SelectEmployee(Employee employee)
+    {
+        selectedEmployee = employee;
+        directReports = null;
+        directReports = await EmployeeService.GetDirectReportsAsync(employee.Id);
+    }
+
+    private static string GetInitials(string name)
+    {
+        var parts = name.Split(' ', StringSplitOptions.RemoveEmptyEntries);
+        if (parts.Length >= 2)
+            return $"{parts[0][0]}{parts[^1][0]}".ToUpper();
+        return parts.Length == 1 ? parts[0][0].ToString().ToUpper() : "?";
+    }
+
+    private static string GetTenureYears(DateTime hireDate)
+    {
+        var tenure = (DateTime.Today - hireDate.Date).TotalDays / 365.25;
+        return tenure.ToString("F1");
+    }
+
+    private static string GetDepartmentColor(string department)
+    {
+        var hash = department.GetHashCode();
+        var hue = Math.Abs(hash % 360);
+        return $"hsl({hue}, 55%, 45%)";
+    }
+}
