    gap: 0.5rem;
}

.employee-card {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem;
    border-radius: 8px;
    cursor: pointer;
    transition: background-color 0.15s;
    border: 1px solid transparent;
}

.employee-card:hover {
    background-color: #f3f4f6;
}

.employee-card.selected {
    background-color: #eff6ff;
    border-color: #3b82f6;
}

.employee-card.clickable:hover {
    background-color: #f0fdf4;
}

/* Avatar */
.avatar-circle {
    width: 40px;
    height: 40px;
    min-width: 40px;
    border-radius: 50%;
    background: linear-gradient(135deg, #6366f1, #8b5cf6);
    color: white;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.85rem;
}

.avatar-circle.large {
    width: 80px;
    height: 80px;
    min-width: 80px;
    font-size: 1.5rem;
}

/* Card Info */
.card-info {
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
    min-width: 0;
}

.card-name {
    font-weight: 600;
    font-size: 0.9rem;
    color: #1f2937;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.card-title {
    font-size: 0.8rem;
    color: #6b7280;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.department-badge {
    display: inline-block;
